import React from 'react';
import './styles/index.css';
import InteractionComponents from './components/InteractionComponents';

function App() {
  return (
    <div className="app-container">
      <h1>Simple AI</h1>
      <InteractionComponents />
    </div>
  );
}

export default App;

body {
  font-family: Arial, sans-serif;
  background-color: #f0f0f0;
}

.app-container {
  max-width: 800px;
  margin: 40px auto;
  padding: 20px;
  background-color: #fff;
  border: 1px solid #ddd;
  box-shadow: 0 0 10px rgba(0, 0, 0, 0.1);
}

.interaction-components {
  margin-top: 20px;
}

import express from 'express';
import { errorHandler } from './src/utils/errorHandler';
import aiRoutes from './src/routes/aiRoutes';
import { PORT } from './src/types';

const app = express();

// Middleware
app.use(express.json());

// Routes
app.use('/api/ai', aiRoutes);

// Error handling
app.use(errorHandler);

// Start server
const startServer = async () => {
  try {
    const port = process.env.PORT || PORT;
    app.listen(port, () => {
      console.log(`Server running on port ${port}`);
    });
  } catch (error) {
    console.error('Failed to start server:', error);
    process.exit(1);
  }
};

startServer();

import { Request, Response, NextFunction } from 'express';
import { AIModel } from '../models/AIModel';
import { AIRequest, AIResponse } from '../types';

export const aiController = {
  async interact(req: Request, res: Response, next: NextFunction) {
    try {
      const { input } = req.body as AIRequest;

      if (!input) {
        throw new Error('Input is required');
      }

      const aiModel = new AIModel();
      const response = await aiModel.generateResponse(input);

      res.json({
        success: true,
        data: {
          response
        }
      });
    } catch (error) {
      next(error);
    }
  }
};

export class AIModel {
  private static instance: AIModel;

  private constructor() {}

  public static getInstance(): AIModel {
    if (!AIModel.instance) {
      AIModel.instance = new AIModel();
    }
    return AIModel.instance;
  }

  public async generateResponse(input: string): Promise<string> {
    // Simple rule-based AI for demonstration
    // This would be replaced with actual AI logic in production
    const lowerInput = input.toLowerCase();

    if (lowerInput.includes('hello') || lowerInput.includes('hi')) {
      return 'Hello! How can I help you today?';
    } else if (lowerInput.includes('how are you')) {
      return 'I\'m a computer program, so I don\'t have feelings, but thanks for asking!';
    } else if (lowerInput.includes('weather')) {
      return 'I currently don\'t have access to real-time weather data.';
    } else {
      return 'I\'m still learning. Can you rephrase that or ask something else?';
    }
  }
}

import express from 'express';
import { aiController } from '../controllers/aiController';

const router = express.Router();

// AI interaction endpoint
router.post('/interact', aiController.interact);

export default router;

export type PORT = 3000 | 5000 | 8000;

export interface AIRequest {
  input: string;
}

export interface AIResponse {
  response: string;
}

export class APIError extends Error {
  status: number;

  constructor(message: string, status: number = 500) {
    super(message);
    this.status = status;
    this.name = 'APIError';
  }
}

import { Request, Response, NextFunction } from 'express';
import { APIError } from '../types';

export const errorHandler = (
  err: Error,
  req: Request,
  res: Response,
  next: NextFunction
) => {
  console.error(err.stack);

  const status = (err instanceof APIError) ? err.status : 500;
  const message = (err instanceof APIError) ? err.message : 'Internal server error';

  res.status(status).json({
    success: false,
    error: {
      message,
      status
    }
  });
};
